"use client";

import { useState, useMemo, useCallback } from "react";
import { Search, Shield, X } from "lucide-react";
import { CATEGORIES } from "@/data/crimes";
import CategorySection from "@/components/CategorySection";
import SummaryPanel from "@/components/SummaryPanel";
import type { CrimeCount } from "@/types";

export default function Home() {
  const [counts, setCounts] = useState<CrimeCount>({});
  const [search, setSearch] = useState("");

  const handleChange = useCallback((id: string, count: number) => {
    setCounts((prev) => {
      if (count === 0) {
        const next = { ...prev };
        delete next[id];
        return next;
      }
      return { ...prev, [id]: count };
    });
  }, []);

  const handleClear = useCallback(() => {
    setCounts({});
    setSearch("");
  }, []);

  const { totalMulta, totalMeses } = useMemo(() => {
    let multa = 0;
    let meses = 0;
    CATEGORIES.forEach((cat) => {
      cat.crimes.forEach((crime) => {
        const q = counts[crime.id] ?? 0;
        multa += crime.multa * q;
        meses += crime.meses * q;
      });
    });
    return { totalMulta: multa, totalMeses: meses };
  }, [counts]);

  const selectedTotal = Object.values(counts).reduce((s, v) => s + v, 0);

  return (
    <div className="min-h-screen bg-slate-950 pb-24">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-slate-950/90 backdrop-blur border-b border-slate-800">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between gap-4">
          <div className="flex items-center gap-3 shrink-0">
            <div className="p-2 rounded-lg bg-blue-600/20 ring-1 ring-blue-600/40">
              <Shield size={20} className="text-blue-400" />
            </div>
            <div>
              <h1 className="text-base font-bold text-white leading-none">Calculadora Penal</h1>
              <p className="text-[11px] text-slate-500 mt-0.5">Fronteira RP</p>
            </div>
          </div>

          {selectedTotal > 0 && (
            <div className="hidden sm:flex items-center gap-2 text-xs text-slate-400">
              <span className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />
              {selectedTotal} {selectedTotal === 1 ? "infração selecionada" : "infrações selecionadas"}
            </div>
          )}

          <div className="relative flex-1 max-w-xs">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Buscar crime..."
              className="w-full bg-slate-800/80 border border-slate-700 rounded-lg pl-8 pr-8 py-1.5 text-sm text-slate-200 placeholder-slate-500 outline-none focus:border-blue-600 focus:ring-1 focus:ring-blue-600/40 transition-all"
            />
            {search && (
              <button
                onClick={() => setSearch("")}
                className="absolute right-2.5 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-300"
              >
                <X size={13} />
              </button>
            )}
          </div>
        </div>
      </header>

      {/* Main content */}
      <main className="max-w-7xl mx-auto px-4 pt-6">
        {CATEGORIES.map((cat) => (
          <CategorySection
            key={cat.id}
            category={cat}
            counts={counts}
            search={search}
            onChange={handleChange}
          />
        ))}

        {search && CATEGORIES.every((cat) =>
          !cat.crimes.some((c) => c.name.toLowerCase().includes(search.toLowerCase()))
        ) && (
          <div className="text-center py-16 text-slate-500">
            <Search size={32} className="mx-auto mb-3 opacity-30" />
            <p className="text-sm">Nenhum crime encontrado para &quot;{search}&quot;</p>
          </div>
        )}
      </main>

      <SummaryPanel
        counts={counts}
        totalMulta={totalMulta}
        totalMeses={totalMeses}
        onClear={handleClear}
      />
    </div>
  );
}
