"use client";

import { Minus, Plus } from "lucide-react";
import { getSeverity, formatMulra } from "@/data/crimes";
import type { Crime } from "@/types";

interface Props {
  crime: Crime;
  count: number;
  onChange: (id: string, count: number) => void;
}

const severityRing = {
  low: "ring-slate-600 hover:ring-blue-500",
  medium: "ring-amber-700 hover:ring-amber-400",
  high: "ring-red-800 hover:ring-red-500",
};

const severitySelected = {
  low: "ring-blue-500 bg-blue-950/60",
  medium: "ring-amber-400 bg-amber-950/60",
  high: "ring-red-500 bg-red-950/60",
};

const severityBadge = {
  low: "bg-blue-900/80 text-blue-300",
  medium: "bg-amber-900/80 text-amber-300",
  high: "bg-red-900/80 text-red-300",
};

const countBubble = {
  low: "bg-blue-500 text-white",
  medium: "bg-amber-500 text-white",
  high: "bg-red-500 text-white",
};

export default function CrimeButton({ crime, count, onChange }: Props) {
  const severity = getSeverity(crime.multa, crime.meses);
  const isSelected = count > 0;

  const toggle = () => onChange(crime.id, isSelected ? 0 : 1);
  const increment = (e: React.MouseEvent) => {
    e.stopPropagation();
    onChange(crime.id, count + 1);
  };
  const decrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    onChange(crime.id, Math.max(0, count - 1));
  };

  return (
    <div
      onClick={toggle}
      className={`
        relative group cursor-pointer rounded-xl p-3 ring-1 transition-all duration-200 select-none
        bg-slate-900 hover:bg-slate-800
        ${isSelected ? severitySelected[severity] : severityRing[severity]}
      `}
    >
      {isSelected && (
        <span
          className={`absolute -top-2 -right-2 w-5 h-5 rounded-full text-[11px] font-bold flex items-center justify-center z-10 ${countBubble[severity]}`}
        >
          {count}
        </span>
      )}

      <div className="flex flex-col gap-1.5">
        <p className={`text-sm font-medium leading-tight ${isSelected ? "text-white" : "text-slate-300"}`}>
          {crime.name}
        </p>

        <div className="flex items-center justify-between gap-2 mt-0.5">
          <div className="flex gap-1.5 flex-wrap">
            <span className={`text-[10px] font-semibold px-1.5 py-0.5 rounded ${severityBadge[severity]}`}>
              {formatMulra(crime.multa)}
            </span>
            <span className="text-[10px] font-semibold px-1.5 py-0.5 rounded bg-slate-800 text-slate-400">
              {crime.meses} meses
            </span>
          </div>

          {isSelected && (
            <div
              className="flex items-center gap-1 shrink-0"
              onClick={(e) => e.stopPropagation()}
            >
              <button
                onClick={decrement}
                className="w-5 h-5 rounded bg-slate-700 hover:bg-slate-600 flex items-center justify-center text-slate-300 transition-colors"
              >
                <Minus size={10} />
              </button>
              <button
                onClick={increment}
                className="w-5 h-5 rounded bg-slate-700 hover:bg-slate-600 flex items-center justify-center text-slate-300 transition-colors"
              >
                <Plus size={10} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
